const body = items[0].json.body || items[0].json;
const serviceType = body.service || 'unknown';
const fields = body.fields || {};

// Service pricing
const pricing = {
  kra: 100,
  ecitizen: 150,
  nhif: 100,
  nssf: 100,
  goodconduct: 200,
  birth: 100
};

// Required fields validation
const requiredFields = {
  kra: ['kra_name', 'kra_id', 'kra_dob'],
  ecitizen: ['ec_name', 'ec_id', 'ec_service'],
  nhif: ['nhif_name', 'nhif_id', 'nhif_phone'],
  nssf: ['nssf_name', 'nssf_id', 'nssf_phone'],
  goodconduct: ['gc_name', 'gc_id', 'gc_dob'],
  birth: ['bc_child', 'bc_dob', 'bc_father', 'bc_mother']
};

const required = requiredFields[serviceType] || [];
const missing = required.filter(f => !fields[f] || fields[f].trim() === '');

return [{
  json: {
    service_type: serviceType,
    fields: fields,
    amount: pricing[serviceType] || 100,
    missing_fields: missing,
    is_valid: missing.length === 0,
    source: body.source || 'kiosk',
    session_id: body.session_id || 'unknown',
    timestamp: new Date().toISOString()
  }
}];

const aiResult = items[0].json.choices?.[0]?.message?.content || '';
const requestData = $('Parse Gov Request').first().json;

return [{
  json: {
    result: aiResult,
    service_type: requestData.service_type,
    customer_name: requestData.fields[requestData.service_type + '_name'] || requestData.fields.ec_name || requestData.fields.gc_name || requestData.fields.bc_child || 'Walk-in',
    phone: requestData.fields[requestData.service_type + '_phone'] || '',
    amount: requestData.amount,
    status: 'pending_approval',
    session_id: requestData.session_id,
    source: requestData.source,
    created_at: new Date().toISOString()
  }
}];
